#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int L[n], R[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &L[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d", &R[i]);
        }
        int maxProduct = 0;
        int maxIndex = 0;
        for (int i = 0; i < n; i++) {
            int product = L[i] * R[i];
            if (product > maxProduct || (product == maxProduct && R[i] > R[maxIndex]) || (product == maxProduct && R[i] == R[maxIndex] && i < maxIndex)) {
                maxProduct = product;
                maxIndex = i;
            }
        }
        printf("%d\n", maxIndex + 1);
    }
    return 0;
}

