import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int[] L = new int[n];
            int[] R = new int[n];
            for (int i = 0; i < n; i++) {
                L[i] = scanner.nextInt();
            }
            for (int i = 0; i < n; i++) {
                R[i] = scanner.nextInt();
            }
            int maxProduct = 0;
            int maxIndex = 0;
            for (int i = 0; i < n; i++) {
                int product = L[i] * R[i];
                if (product > maxProduct || (product == maxProduct && R[i] > R[maxIndex]) || (product == maxProduct && R[i] == R[maxIndex] && i < maxIndex)) {
                    maxProduct = product;
                    maxIndex = i;
                }
            }
            System.out.println(maxIndex + 1);
        }
    }
}

